const MEETING_MIN = 50;
const PRE_BUF_MIN = 10;
const MIN = 60 * 1000;
const MEETING_MS = MEETING_MIN * MIN;
const PRE_BUF_MS = PRE_BUF_MIN * MIN;

const EVENT_TZ = 'America/Sao_Paulo';
const CLIENT_TZ = 'America/Sao_Paulo';

// --- Cached formatters (avoid recreating in loops) ---
const fmtDateClient = new Intl.DateTimeFormat('en-CA', { timeZone: CLIENT_TZ, year: 'numeric', month: '2-digit', day: '2-digit' });
const fmtTimeClient = new Intl.DateTimeFormat('en-GB', { timeZone: CLIENT_TZ, hour: '2-digit', minute: '2-digit', hour12: false });
const fmtWeekdayClient = new Intl.DateTimeFormat('en-GB', { timeZone: CLIENT_TZ, weekday: 'short' });

const fmtDateByTz = {
  [CLIENT_TZ]: fmtDateClient,
};
const fmtTimeByTz = {
  [CLIENT_TZ]: fmtTimeClient,
};
const fmtWeekdayByTz = {
  [CLIENT_TZ]: fmtWeekdayClient,
};

// Helpers use cached formatters
function datePartsInTz(ts, tz) {
  const [y, m, d] = (fmtDateByTz[tz] || new Intl.DateTimeFormat('en-CA', { timeZone: tz, year: 'numeric', month: '2-digit', day: '2-digit' }))
    .format(new Date(ts)).split('-').map(Number);
  return { y, m, d };
}

function atTimeInTz(ts, h, m, tz) {
  const { y, m: mo, d } = datePartsInTz(ts, tz);
  const approx = Date.UTC(y, mo - 1, d, h, m, 0, 0);
  const shownHM = (fmtTimeByTz[tz] || new Intl.DateTimeFormat('en-GB', { timeZone: tz, hour: '2-digit', minute: '2-digit', hour12: false }))
    .format(new Date(approx)).split(':').map(Number);
  const diffMin = (shownHM[0] - h) * 60 + (shownHM[1] - m);
  return approx - diffMin * MIN;
}

function isWeekendInTz(ts, tz) {
  const wd = (fmtWeekdayByTz[tz] || new Intl.DateTimeFormat('en-GB', { timeZone: tz, weekday: 'short' }))
    .format(new Date(ts));
  return wd === 'Sun'; // Apenas domingo é considerado final de semana
}

function isSaturdayInTz(ts, tz) {
  const wd = (fmtWeekdayByTz[tz] || new Intl.DateTimeFormat('en-GB', { timeZone: tz, weekday: 'short' }))
    .format(new Date(ts));
  return wd === 'Sat';
}

function mergeIntervals(a) {
  if (!a.length) return [];
  a.sort((x, y) => x.start - y.start);
  const m = [a[0]];
  for (let i = 1; i < a.length; i++) {
    const p = m[m.length - 1], c = a[i];
    if (c.start <= p.end) p.end = Math.max(p.end, c.end);
    else m.push({ ...c });
  }
  return m;
}

function invertBusy(start, end, blocks) {
  const out = [];
  let cur = start;
  for (const b of blocks) {
    const s = Math.max(b.start, start), e = Math.min(b.end, end);
    if (e <= start || s >= end) continue;
    if (s > cur) out.push({ start: cur, end: s });
    cur = Math.max(cur, e);
  }
  if (cur < end) out.push({ start: cur, end: end });
  return out;
}

// Safe next-day in client TZ (strictly increases)
function nextClientDay00(ts) {
  const { y, m, d } = datePartsInTz(ts, CLIENT_TZ);
  // Construct "next day 00:00" in CLIENT_TZ
  const nextApproxUTC = Date.UTC(y, m - 1, d + 1, 0, 0, 0, 0);
  // Snap to exactly 00:00 CLIENT_TZ via correction
  const nextDay = atTimeInTz(nextApproxUTC, 0, 0, CLIENT_TZ);

  // Safety check: ensure we're actually moving forward
  if (nextDay <= ts) {
    // Fallback: add 25 hours to guarantee progression
    return ts + 25 * 3600 * 1000;
  }

  return nextDay;
}

// --- Collect and clamp inputs ---
const eventos = items.flatMap(i => Array.isArray(i.json?.eventos) ? i.json.eventos : []);
const now = Date.now();
const endWin = now + 14 * 24 * 3600 * 1000;

// Busy = [eventStart - 10m, eventEnd] (pre-buffer only)
const busyRaw = [];
for (const e of eventos) {
  const s = Date.parse(e?.start?.dateTime || e?.start?.date);
  const t = Date.parse(e?.end?.dateTime || e?.end?.date);
  if (!isNaN(s) && !isNaN(t)) {
    const b = { start: s - PRE_BUF_MS, end: t };
    if (b.end > now && b.start < endWin) busyRaw.push(b);
  }
}
const busy = mergeIntervals(busyRaw);

// --- Build weekday working windows in Brasília (08:00–18:00, sábado 08:00-12:00) ---
const days = [];
let cursor = now;
let guard = 0;
const MAX_ITERATIONS = 14; // 7 dias * 2 de margem de segurança

while (cursor < endWin && guard++ < MAX_ITERATIONS) {
  const isSaturday = isSaturdayInTz(cursor, CLIENT_TZ);
  const dayStart = atTimeInTz(cursor, 7, 0, CLIENT_TZ);
  const dayEnd = isSaturday 
    ? atTimeInTz(cursor, 12, 0, CLIENT_TZ)  // Sábado até 12h
    : atTimeInTz(cursor, 20, 0, CLIENT_TZ); // Dias de semana até 20h

  if (!isWeekendInTz(dayStart, CLIENT_TZ)) { // Agora exclui apenas domingo
    let start = dayStart;
    let end = dayEnd;

    // If this is "today" in CLIENT_TZ, earliest start is now + 10m
    const sameClientDate = fmtDateClient.format(new Date(dayStart)) === fmtDateClient.format(new Date(now));
    if (sameClientDate) start = Math.max(start, now + PRE_BUF_MS);

    // clamp to global window
    start = Math.max(start, now);
    end = Math.min(end, endWin);

    if (end > start) days.push({ start, end });
  }

  const next = nextClientDay00(cursor);

  // Hard safety check: ensure progression
  if (next <= cursor) {
    console.error('Loop detection: nextClientDay00 did not advance. Breaking.');
    cursor += 26 * 3600 * 1000; // Force advance by 26 hours
  } else {
    cursor = next;
  }
}

// Safety warning if we hit the guard
if (guard >= MAX_ITERATIONS) {
  console.warn(`Hit iteration limit (${MAX_ITERATIONS}). Processed ${days.length} days.`);
}

// --- Compute availability (start-time windows) per day ---
const availability = [];
for (const d of days) {
  const dayBusy = mergeIntervals(
    busy
      .filter(b => b.end > d.start && b.start < d.end)
      .map(b => ({ start: Math.max(b.start, d.start), end: Math.min(b.end, d.end) }))
  );

  const free = invertBusy(d.start, d.end, dayBusy);

  // Convert free-time to valid START windows (must fit a 50-min call)
  const startWindows = [];
  for (const g of free) {
    const s = g.start;
    const e = g.end - MEETING_MS;
    if (e > s) startWindows.push({ start: s, end: e });
  }

  if (startWindows.length) {
    availability.push({
      date: fmtDateClient.format(new Date(d.start)),
      available: startWindows.map(w => ({
        start: fmtTimeClient.format(new Date(w.start)),
        end: fmtTimeClient.format(new Date(w.end)),
      })),
    });
  }
}

// --- Single aggregated item for n8n ---
return [{ json: { availability, calendarioId: $('calendario').first().json.nome } }];

